            <div style="display: flex; align-items: center; gap: 8px;">
              ${n.innerHTML}
              <span style="font-weight: 600; color: ${this.styles.accentColor};">${this.business.rating.toFixed(1)}</span>
              <span style="color: ${this.styles.textColor}; opacity: 0.6; font-size: 14px;">(${this.business.totalReviews} reviews)</span>
            </div>
