  /* ===== Animator (class o) ===== */
  class o {
    constructor(t, e = {}) {
      this.container = t;
      this.observer = null;
      this.animationStyle = e.animationStyle || "slideUp";
    }

    observe(t, e, s = 0.1) {
      this.observer = new IntersectionObserver(
        t => {
          t.forEach(t => {
            if (t.isIntersecting) {
              t.target.classList.add(e);
              t.target.style.opacity = "1";
              t.target.style.transform = "translateY(0) scale(1)";
            }
          });
        },
        { threshold: s }
      );

      t.forEach(t => {
        if (this.animationStyle === "none") return;

        if (this.animationStyle === "fadeIn") {
          t.style.opacity = "0";
          t.style.transform = "none";
          t.style.transition = "opacity 0.6s ease";
        } else if (this.animationStyle === "scaleIn") {
          t.style.opacity = "0";
          t.style.transform = "scale(0.9)";
          t.style.transition = "opacity 0.6s ease, transform 0.6s ease";
        } else {
          /* slideUp (default) */
          t.style.opacity = "0";
          t.style.transform = "translateY(20px)";
          t.style.transition = "opacity 0.6s ease, transform 0.6s ease";
        }

        this.observer.observe(t);
      });
    }

    addHoverEffect(t, e = 1.02, s = true) {
      t.addEventListener("mouseenter", () => {
        t.style.transform = `scale(${e})`;
        if (s) t.style.boxShadow = "0 8px 30px rgba(0,0,0,0.12)";
      });
      t.addEventListener("mouseleave", () => {
        t.style.transform = "scale(1)";
        if (s) t.style.boxShadow = "";
      });
    }

    autoScroll(t, e = 5e3) {
      let s;
      const n = () => {
        s = setInterval(() => {
          t.scrollLeft += 1;
        }, 20);
      };
      t.addEventListener("mouseenter", () => clearInterval(s));
      t.addEventListener("mouseleave", n);
      n();
    }
  }

